1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	};
7	
8	type Item = { type: string };
9	type QuoteStep = { op: "quote"; items: Item[] };
10	type Step = QuoteStep;
11	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
12	
13	const basePremium = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
14	
15	const quotePremium = (items: Item[]): number =>
16	  items.reduce((sum, item) => sum + basePremium(item), 0) + PROCESSING_FEE;
17	
18	export const runScenario = (input: Scenario): { results: { premium: number }[] } => ({
19	  results: input.steps.map((step) => ({ premium: quotePremium(step.items) })),
20	});
21

1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Empty / trivial ---
6	  it("empty item list yields premium 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Base premiums by item type ---
15	  it("quote for a single plain sword yields 105 G (100 base + 5 fee)", () => {
16	    const result = runScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	    });
20	    expect(result).toEqual({ results: [{ premium: 105 }] });
21	  });
22	  it("quote for a single plain amulet yields 65 G (60 base + 5 fee)", () => {
23	    const result = runScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
26	    });
27	    expect(result).toEqual({ results: [{ premium: 65 }] });
28	  });
29	  it.todo("quote for a single plain staff yields 85 G (80 base + 5 fee)");
30	  it.todo("quote for a single plain potion yields 45 G (40 base + 5 fee)");
31	
32	  // --- Components and building blocks ---
33	  it.todo("quote for 1 rune yields 30 G (25 base + 5 fee)");
34	  it.todo("quote for 2 runes yields 55 G (50 base + 5 fee)");
35	  it.todo("quote for 3 runes yields 65 G — block applies (60 base + 5 fee)");
36	  it.todo("quote for 4 runes yields 105 G — no block (100 base + 5 fee)");
37	  it.todo("quote for 7 runes yields 180 G (175 base + 5 fee)");
38	  it.todo("quote for 2 runes + 1 moonstone yields 80 G — no block, different types (75 base + 5 fee)");
39	  it.todo("quote for 3 runes + 3 moonstones yields 125 G — two separate blocks (120 base + 5 fee)");
40	
41	  // --- Item-specific modifiers ---
42	  it.todo("cursed sword (no other modifiers, newcomer's first contract) yields 165 G");
43	  it.todo("sword with enchantment 5 adds 30% high-enchantment surcharge");
44	  it.todo("sword with enchantment 4 does NOT add high-enchantment surcharge");
45	  it.todo("cursed sword with enchantment 5 adds both curse and high-enchantment surcharges");
46	
47	  // --- Policy-wide modifiers ---
48	  it.todo("customer with exactly 2 years gets 20% loyalty discount");
49	  it.todo("customer with less than 2 years does not get loyalty discount");
50	  it.todo("first contract in scenario gets 10% first-insurance surcharge per item");
51	  it.todo("second contract in scenario gets 15% follow-up discount on policy total");
52	
53	  // --- Modifier scope on multi-item policies ---
54	  it.todo("cursed sword + plain amulet: curse applies only to sword (base 160, +50 = 210 before fee)");
55	
56	  // --- Rounding ---
57	  it.todo("premium fractional result rounds UP in MHPCO's favor (197.5 -> 198)");
58	  it.todo("payout fractional result rounds DOWN in MHPCO's favor (350.5 -> 350)");
59	
60	  // --- Integration examples ---
61	  it.todo("newcomer with cursed sword (enchantment 3, 0 years): premium 165 G");
62	  it.todo("long-standing customer's second contract with cursed sword (enchantment 7, 3 years): premium 160 G");
63	
64	  // --- Claim processing: standard reimbursement ---
65	  it.todo("regular steel sword enchantment 3 damaged 500 G yields payout 400 G (500 - 100 deductible)");
66	  it.todo("rune damaged 200 G yields payout 100 G (no special clause, deductible 100)");
67	
68	  // --- Claim processing: high enchantment ---
69	  it.todo("steel sword enchantment 9 damaged 1000 G yields payout 400 G (50% then -100)");
70	  it.todo("dragon sword enchantment 8 damaged 1000 G yields payout 400 G (50% wins, then -100)");
71	
72	  // --- Claim processing: dragon material ---
73	  it.todo("dragon sword enchantment 5 damaged 800 G yields payout 700 G (full, then -100)");
74	  it.todo("dragon sword enchantment 9 damaged 1000 G yields payout 400 G (50% wins, then -100)");
75	
76	  // --- Deductible per damage event ---
77	  it.todo("two items damaged by dragon: 500 + 300 -> 400 + 200 = 600 G (deductible per item)");
78	
79	  // --- Multiple items of the same type ---
80	  it.todo("two swords -> insurance sum 2000, cap 4000");
81	  it.todo("two sword damages on a two-sword policy: each treated separately");
82	  it.todo("more damages of a type than insured items rejects the claim (CLI non-zero exit)");
83	
84	  // --- Cap exhaustion ---
85	  it.todo("sword + amulet -> insurance sum 1600, cap 3200");
86	  it.todo("cursed sword -> cap 2000 (premium modifiers don't change cap)");
87	  it.todo("sword + 3 runes (block) -> insurance sum 1750 (block affects premium only)");
88	  it.todo("two successive 1500 G claims on sword (cap 2000): payouts 1400 then 600, remaining 0");
89	
